import { describe, expect, it, vi } from "vitest";

vi.mock("next/headers", () => ({
  cookies: () => ({ get: (n: string) => (n === "pharmacy-session" ? { value: "r-pilot-1" } : undefined) }),
}));

import { GET } from "./route";

interface SearchResult {
  id: string;
  name: string;
  brand: string;
  genericName: string;
  distributor: { id: string; name: string };
  mrpPaise: number;
  sellingPricePaise: number;
  scheme: string | null;
  packSize: string;
}

describe("GET /api/medicines/search (authenticated)", () => {
  it("empty q returns the catalogue", async () => {
    const res = await GET(new Request("http://localhost/api/medicines/search"));
    expect(res.status).toBe(200);
    const body = (await res.json()) as { results: SearchResult[] };
    expect(body.results.length).toBeGreaterThan(0);
    const sample = body.results[0];
    expect(sample).toHaveProperty("id");
    expect(sample).toHaveProperty("distributor.id");
    expect(sample).toHaveProperty("distributor.name");
    expect(typeof sample.mrpPaise).toBe("number");
    expect(typeof sample.sellingPricePaise).toBe("number");
  });

  it("q filters case-insensitively", async () => {
    const res = await GET(new Request("http://localhost/api/medicines/search?q=PARACET"));
    const body = (await res.json()) as { results: SearchResult[] };
    expect(body.results.length).toBeGreaterThanOrEqual(1);
    expect(body.results.some((r) => /paracetamol/i.test(r.name))).toBe(true);
  });
});
